('c1000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', 1, 'fill_blank', '[Complete the summary. Choose from: Mexicans / random / rotating / despite / preserve / realising / sunlight / lacking / heavenly / percussion / chance / friction / unaware / without / make / heating / Eskimos / surprised / until / smoke] Primitive societies tried to ___ (1) burning logs or charcoal', 'preserve', 1),
('c1000000-0000-0000-0000-000000000002', 'b1000000-0000-0000-0000-000000000001', 2, 'fill_blank', '[Complete the summary. Choose from: Mexicans / random / rotating / despite / preserve / realising / sunlight / lacking / heavenly / percussion / chance / friction / unaware / without / make / heating / Eskimos / surprised / until / smoke] They stored fire ___ (2) that they could not create fire themselves.', 'unaware', 1),
