('c1000000-0000-0000-0000-000000000036', 'b1000000-0000-0000-0000-000000000003', 36, 'matching', '[Match each Cause with its Effect. A=quality of life improved B=architecture reflects the age C=buildings knocked down D=light steel frames and lifts developed E=historical buildings preserved F=all decoration removed G=parts of cities become slums H=Modernist ideas delayed until second half of 20th century] Rapid movement of people from rural areas to cities triggered by technological advance.', 'G', 1),
('c1000000-0000-0000-0000-000000000037', 'b1000000-0000-0000-0000-000000000003', 37, 'matching', '[Match each Cause with its Effect. A=quality of life improved B=architecture reflects the age C=buildings knocked down D=light steel frames and lifts developed E=historical buildings preserved F=all decoration removed G=parts of cities become slums H=Modernist ideas delayed until second half of 20th century] Buildings become simple and functional.', 'F', 1),
('c1000000-0000-0000-0000-000000000038', 'b1000000-0000-0000-0000-000000000003', 38, 'matching', '[Match each Cause with its Effect. A=quality of life improved B=architecture reflects the age C=buildings knocked down D=light steel frames and lifts developed E=historical buildings preserved F=all decoration removed G=parts of cities become slums H=Modernist ideas delayed until second half of 20th century] An economic depression and the second world war hit Europe.', 'H', 1),
('c1000000-0000-0000-0000-000000000039', 'b1000000-0000-0000-0000-000000000003', 39, 'matching', '[Match each Cause with its Effect. A=quality of life improved B=architecture reflects the age C=buildings knocked down D=light steel frames and lifts developed E=historical buildings preserved F=all decoration removed G=parts of cities become slums H=Modernist ideas delayed until second half of 20th century] Multi-storey housing estates built according to contemporary ideas on town planning.', 'C', 1),
('c1000000-0000-0000-0000-000000000040', 'b1000000-0000-0000-0000-000000000003', 40, 'matching', '[Match each Cause with its Effect. A=quality of life improved B=architecture reflects the age C=buildings knocked down D=light steel frames and lifts developed E=historical buildings preserved F=all decoration removed G=parts of cities become slums H=Modernist ideas delayed until second half of 20th century] Less land must be used for building.', 'D', 1);